async function seedColleges() {
  try {
    // Check connection state or connect
    if (mongoose.connection.readyState === 0) {
      await connectDB();
    }

    // Deduplicate collegesData by name and city before processing
    const uniqueColleges = [];
    const seenNames = new Set();
    for (const c of collegesData) {
      const uniqueKey = `${c.name.trim()}-${c.city.trim()}`.toLowerCase();
      if (!seenNames.has(uniqueKey)) {
        seenNames.add(uniqueKey);
        uniqueColleges.push(c);
      }
    }

    console.log(`🌱 Processing ${uniqueColleges.length} unique colleges for upsert (no deletion)...`);
    
    let insertedCount = 0;
    let skippedCount = 0;

    for (const c of uniqueColleges) {
      // Case-insensitive check for name and city
      const result = await College.updateOne(
        {
          name: { $regex: `^${c.name.trim().replace(/[-\/\\^$*+?.()|[\]{}]/g, '\\$&')}$`, $options: "i" },
          city: { $regex: `^${c.city.trim().replace(/[-\/\\^$*+?.()|[\]{}]/g, '\\$&')}$`, $options: "i" }
        },
        { $setOnInsert: c },
        { upsert: true }
      );

      if (result.upsertedCount > 0) {
        insertedCount++;
      } else {
        skippedCount++;
      }
    }

    console.log(`✅ Seeding complete: Added ${insertedCount} new colleges, Skipped ${skippedCount} existing/duplicate colleges.`);

  } catch (error) {
    console.error("❌ Seeding colleges failed:", error.message);
  } finally {
    // If we connected within the script, we close the connection
    if (mongoose.connection.readyState !== 0) {
      await mongoose.disconnect();
      console.log("🔌 MongoDB disconnected");
    }
  }
}

// Run the script directly if invoked from command line
if (require.main === module) {
  seedColleges().then(() => {
    process.exit(0);
  }).catch((err) => {
    console.error("Fatal seed error:", err);
    process.exit(1);
  });
}

module.exports = seedColleges;
